import { promises as fs } from "node:fs";
import path from "node:path";
import {
  createWorkspace,
  teardownWorkspace,
  type Workspace,
} from "@tigrisdata/agent-kit";
import { S3Client, PutObjectCommand } from "@aws-sdk/client-s3";

const STATE_FILE = path.resolve(
  path.dirname(new URL(import.meta.url).pathname),
  "pool-state.json"
);

const TIGRIS_ENDPOINT = "REDACTED";

export type PoolEntry = {
  name: string;
  bucket: string;
  credentials: {
    accessKeyId: string;
    secretAccessKey: string;
  };
};

export type PoolState = {
  workspaces: PoolEntry[];
};

async function readState(): Promise<PoolState> {
  const raw = await fs.readFile(STATE_FILE, "utf8");
  return JSON.parse(raw) as PoolState;
}

async function writeState(state: PoolState): Promise<void> {
  await fs.writeFile(STATE_FILE, JSON.stringify(state, null, 2), "utf8");
}

export async function provisionPool(n: number): Promise<void> {
  if (!Number.isInteger(n) || n <= 0) {
    throw new Error(`provision: <N> must be a positive integer, got "${n}"`);
  }

  const names = Array.from({ length: n }, (_, i) => `pool-${n}-${i + 1}`);

  const results = await Promise.all(
    names.map((name) =>
      createWorkspace(name, {
        ttl: { days: 1 },
        credentials: { role: "Editor" },
      })
    )
  );

  const entries: PoolEntry[] = [];
  const errors: string[] = [];
  results.forEach((res, i) => {
    if (res.error) {
      errors.push(`workspace ${names[i]}: ${res.error.message ?? res.error}`);
    } else {
      const ws = res.data as Workspace;
      if (!ws.credentials) {
        errors.push(
          `workspace ${names[i]}: missing scoped credentials in response`
        );
        return;
      }
      entries.push({
        name: names[i],
        bucket: ws.bucket,
        credentials: {
          accessKeyId: ws.credentials.accessKeyId,
          secretAccessKey: ws.credentials.secretAccessKey,
        },
      });
    }
  });

  if (errors.length > 0) {
    throw new Error(`provision failed:\n  ${errors.join("\n  ")}`);
  }

  await writeState({ workspaces: entries });
  console.log(`provisioned ${entries.length} workspace(s):`);
  for (const e of entries) {
    console.log(`  ${e.name} -> ${e.bucket}`);
  }
}

export async function assignTask(
  agentIndex: number,
  text: string
): Promise<void> {
  if (!Number.isInteger(agentIndex) || agentIndex <= 0) {
    throw new Error(
      `assign-task: <agent-index> must be a positive integer, got "${agentIndex}"`
    );
  }

  const state = await readState();
  const entry = state.workspaces[agentIndex - 1];
  if (!entry) {
    throw new Error(
      `assign-task: agent index ${agentIndex} is out of range (pool size ${state.workspaces.length})`
    );
  }

  const client = new S3Client({
    endpoint: TIGRIS_ENDPOINT,
    region: "REDACTED",
    credentials: {
      accessKeyId: entry.credentials.accessKeyId,
      secretAccessKey: entry.credentials.secretAccessKey,
    },
  });

  await client.send(
    new PutObjectCommand({
      Bucket: entry.bucket,
      Key: "task.txt",
      Body: text,
    })
  );

  console.log(`assigned task to ${entry.name} (${entry.bucket}): task.txt`);
}

export async function status(): Promise<void> {
  const state = await readState();
  console.log(`pool size: ${state.workspaces.length}`);
  for (const entry of state.workspaces) {
    console.log(entry.bucket);
  }
}

export async function teardownPool(): Promise<void> {
  const state = await readState();

  const results = await Promise.allSettled(
    state.workspaces.map((entry) =>
      teardownWorkspace({
        bucket: entry.bucket,
        credentials: entry.credentials,
      }).then((res) => {
        if (res.error) throw res.error;
        return res.data;
      })
    )
  );

  const failures: string[] = [];
  results.forEach((res, i) => {
    const entry = state.workspaces[i];
    if (res.status === "rejected") {
      failures.push(
        `${entry.name} (${entry.bucket}): ${
          (res.reason as Error)?.message ?? res.reason
        }`
      );
    } else {
      console.log(`torn down ${entry.name} (${entry.bucket})`);
    }
  });

  try {
    await fs.unlink(STATE_FILE);
  } catch (err: any) {
    if (err?.code !== "ENOENT") {
      throw err;
    }
  }

  if (failures.length > 0) {
    throw new Error(`teardown failures:\n  ${failures.join("\n  ")}`);
  }
}

import {
  provisionPool,
  assignTask,
  status,
  teardownPool,
} from "./manager.ts";

const USAGE = `Usage:
  npx tsx cli.ts provision <N>
  npx tsx cli.ts assign-task <agent-index> <text>
  npx tsx cli.ts status
  npx tsx cli.ts teardown`;

async function main(): Promise<void> {
  const [subcommand, ...args] = process.argv.slice(2);

  if (!subcommand) {
    process.stderr.write(USAGE + "\n");
    process.exitCode = 1;
    return;
  }

  switch (subcommand) {
    case "provision": {
      if (args.length !== 1) {
        process.stderr.write(`provision requires exactly one argument <N>\n${USAGE}\n`);
        process.exitCode = 1;
        return;
      }
      const n = Number.parseInt(args[0], 10);
      if (!Number.isFinite(n)) {
        process.stderr.write(`provision: <N> must be a positive integer\n`);
        process.exitCode = 1;
        return;
      }
      await provisionPool(n);
      return;
    }
    case "assign-task": {
      if (args.length !== 2) {
        process.stderr.write(
          `assign-task requires exactly two arguments <agent-index> <text>\n${USAGE}\n`
        );
        process.exitCode = 1;
        return;
      }
      const idx = Number.parseInt(args[0], 10);
      if (!Number.isFinite(idx)) {
        process.stderr.write(`assign-task: <agent-index> must be a positive integer\n`);
        process.exitCode = 1;
        return;
      }
      await assignTask(idx, args[1]);
      return;
    }
    case "status": {
      await status();
      return;
    }
    case "teardown": {
      await teardownPool();
      return;
    }
    default: {
      process.stderr.write(`Unknown subcommand: ${subcommand}\n${USAGE}\n`);
      process.exitCode = 1;
      return;
    }
  }
}

main().catch((err: unknown) => {
  const msg = err instanceof Error ? err.stack ?? err.message : String(err);
  process.stderr.write(`error: ${msg}\n`);
  process.exitCode = 1;
});

